class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
        escape_shell: bool = False,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = (
            process_priority if process_priority in _PRIORITY_TO_NICE else None
        )
        self.escape_shell = escape_shell

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _apply_process_priority(self, pid: int) -> None:
        """Best-effort attempt to set the priority of the editor
        process.  Any failure is ignored since the edit operation
        should succeed even if the priority could not be changed.
        """
        if self.process_priority is None:
            return

