                nice_value = _PRIORITY_TO_NICE[self.process_priority]
                os.setpriority(os.PRIO_PROCESS, pid, nice_value)
        except Exception:
            # Priority setting is best-effort; failures should never
            # cause the edit operation itself to fail.
            pass

